SELECT resort_id, lift_type, COUNT(*) AS lift_count
FROM lifts
GROUP BY resort_id, lift_type;

SELECT lift_name, lift_type
FROM lifts
WHERE lift_type = 'Gondola';

SELECT trail_name, difficulty
FROM trails
ORDER BY difficulty ASC;

SELECT * 
FROM employees 
ORDER BY last_updated ASC;

SELECT first_name, last_name
FROM employees
WHERE employee_experience_years > (SELECT AVG(employee_experience_years) FROM employees);

SELECT COUNT(*) AS TotalLifts
FROM lifts
WHERE lift_type = 'Chairlift';
